    // Navigate
    window.location.href = 'https://www.commonapp.org/explore';
    // Poll for school elements to appear
    const poll = (sel, timeout) => new Promise((resolve, reject) => {
        const start = Date.now();
        const check = () => {
            const els = document.querySelectorAll(sel);
            if (els.length > 0) return resolve(els);
            if (Date.now() - start > timeout) return reject(new Error('timeout'));
