package platform

import (
	"context"
	"fmt"
	"strings"
)

const (
	commonAppURL = "https://www.commonapp.org/explore"

	// commonAppMinExpected is the minimum number of institutions we expect.
	// Common App has ~1100 members; fewer suggests a scraping failure.
	commonAppMinExpected = 900
)

// extractJS is a self-contained JavaScript expression that fetches the Common
// App explore page and extracts institution names. Because the Browser
// implementation runs Navigate and EvalStrings in separate tabs, this JS must
// fetch the page itself rather than relying on prior navigation state.
//
// Strategy: fetch the explore page HTML, parse the __NEXT_DATA__ JSON payload
// that Next.js embeds in the page, and extract school names from it. Falls back
// to trying known API endpoint patterns.
const extractJS = `(async () => {
	// Strategy 1: Fetch explore page and parse __NEXT_DATA__ (Next.js embed).
	try {
		const resp = await fetch("https://www.commonapp.org/explore");
		const html = await resp.text();
		const match = html.match(/<script id="__NEXT_DATA__"[^>]*>([\s\S]*?)<\/script>/);
		if (match) {
			const data = JSON.parse(match[1]);
			// Walk the props tree looking for an array of school objects.
			const find = (obj) => {
				if (!obj || typeof obj !== 'object') return null;
				if (Array.isArray(obj) && obj.length > 100 && obj[0] && (obj[0].name || obj[0].schoolName || obj[0].collegeName || obj[0].institution_name)) {
					const key = obj[0].name ? 'name' : obj[0].schoolName ? 'schoolName' : obj[0].collegeName ? 'collegeName' : 'institution_name';
					return obj.map(s => s[key]).filter(Boolean);
				}
				for (const v of Object.values(obj)) {
					const r = find(v);
					if (r) return r;
				}
				return null;
			};
			const names = find(data);
			if (names && names.length > 100) return names;
		}
	} catch (e) { /* continue to next strategy */ }

	// Strategy 2: Try common API endpoints.
	const endpoints = [
		"https://www.commonapp.org/api/explore",
		"https://www.commonapp.org/api/colleges",
		"https://www.commonapp.org/api/explore/colleges",
		"https://www.commonapp.org/api/search",
	];
	for (const ep of endpoints) {
		try {
			const resp = await fetch(ep);
			if (!resp.ok) continue;
			const data = await resp.json();
			const arr = Array.isArray(data) ? data : (data.results || data.colleges || data.schools || data.data || []);
			if (arr.length > 100) {
				return arr.map(s => s.name || s.schoolName || s.collegeName || s.title || "").filter(Boolean);
			}
		} catch (e) { /* try next */ }
	}

	// Strategy 3: Fetch the page and try to extract from rendered markup patterns.
	try {
		const resp = await fetch("https://www.commonapp.org/explore");
		const html = await resp.text();
		// Look for JSON data embedded in script tags (non-__NEXT_DATA__).
		const scripts = [...html.matchAll(/<script[^>]*>([\s\S]*?)<\/script>/g)];
		for (const [, body] of scripts) {
			if (body.length < 500) continue;
			try {
				const data = JSON.parse(body);
				const find = (obj, depth) => {
					if (depth > 5 || !obj || typeof obj !== 'object') return null;
					if (Array.isArray(obj) && obj.length > 100 && obj[0] && typeof obj[0] === 'object') {
						for (const key of ['name', 'schoolName', 'collegeName', 'institution_name', 'title']) {
							if (obj[0][key]) return obj.map(s => s[key]).filter(Boolean);
						}
					}
					for (const v of Object.values(obj)) {
						const r = find(v, depth + 1);
						if (r) return r;
					}
					return null;
				};
				const names = find(data, 0);
				if (names && names.length > 100) return names;
			} catch (e) { /* not JSON, skip */ }
		}
	} catch (e) { /* give up */ }

	return [];
})()`

// commonApp implements Extractor for the Common App explore page.
type commonApp struct{}

// NewCommonApp returns an Extractor that scrapes Common App member institutions
// from commonapp.org/explore.
func NewCommonApp() Extractor {
	return &commonApp{}
}

func (c *commonApp) Key() string   { return KeyCommon }
func (c *commonApp) Label() string { return "Common App" }

func (c *commonApp) Extract(ctx context.Context, browser Browser) ([]string, error) {
	// Navigate to warm up the browser session (cookies, etc.).
	// The tab closes after Navigate returns, but cookies persist across tabs.
	if err := browser.Navigate(ctx, commonAppURL); err != nil {
		return nil, fmt.Errorf("platform: commonapp: navigate: %w", err)
	}

	// Run self-contained JS that fetches and parses the data.
	names, err := browser.EvalStrings(ctx, extractJS)
	if err != nil {
		return nil, fmt.Errorf("platform: commonapp: eval: %w", err)
	}

	unique := deduplicate(names)
	if len(unique) < commonAppMinExpected {
		return unique, fmt.Errorf("platform: commonapp: got %d names, expected at least %d", len(unique), commonAppMinExpected)
	}

	return unique, nil
}

// deduplicate removes empty strings, trims whitespace, and removes duplicates
// while preserving order.
func deduplicate(names []string) []string {
	seen := make(map[string]bool, len(names))
	result := make([]string, 0, len(names))
	for _, name := range names {
		name = strings.TrimSpace(name)
		if name == "" || seen[name] {
			continue
		}
		seen[name] = true
		result = append(result, name)
	}
	return result
}

