)

// mockBrowser implements Browser for testing extractors.
type mockBrowser struct {
	navigateErr error
	evalResults []string
	evalErr     error
}

func (m *mockBrowser) Navigate(_ context.Context, _ string) error {
	return m.navigateErr
}

func (m *mockBrowser) EvalStrings(_ context.Context, _ string) ([]string, error) {
	if m.evalErr != nil {
		return nil, m.evalErr
	}
